function gcdOfStrings(str1, str2) {
  function gcd(a, b) {
    while (b !== 0) {
      [a, b] = [b, a % b];
    }
    return a;
  }

  if (str1 + str2 !== str2 + str1) {
    return '';
  }

  const gcdLen = gcd(str1.length, str2.length);
  return str1.substring(0, gcdLen);
}

